arguments.file_text:
namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings == 0 ? 0 : (double)RatingSum / TotalRatings;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious pizza with fresh mozzarella, tomatoes, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = [
                    "Preheat oven to 475°F (245°C) with a pizza stone inside.",
                    "Stretch dough into a 12-inch round on a floured surface.",
                    "Spread crushed tomatoes evenly over the dough.",
                    "Tear mozzarella into pieces and distribute over the sauce.",
                    "Bake for 10–12 minutes until crust is golden and cheese is bubbly.",
                    "Top with fresh basil leaves, drizzle with olive oil, and serve."
                ],
                TotalRatings = 12, RatingSum = 52
            },
            new Recipe
            {
                Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a creamy, spiced tomato sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Turmeric", "Cumin", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = [
                    "Marinate chicken in yogurt, garam masala, turmeric, and cumin for at least 1 hour.",
                    "Grill or broil the chicken until charred and cooked through.",
                    "Sauté diced onion, garlic, and ginger in oil until softened.",
                    "Add tomato sauce and remaining spices; simmer for 15 minutes.",
                    "Stir in heavy cream and add the cooked chicken pieces.",
                    "Simmer for 10 more minutes and serve over basmati rice."
                ],
                TotalRatings = 8, RatingSum = 38
            },
            new Recipe
            {
                Id = 3, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef tacos with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = [
                    "Brown ground beef in a skillet over medium-high heat.",
                    "Add taco seasoning and water; simmer until thickened.",
                    "Warm tortillas in a dry skillet or microwave.",
                    "Fill tortillas with seasoned beef.",
                    "Top with shredded lettuce, diced tomato, cheese, sour cream, and salsa."
                ],
                TotalRatings = 15, RatingSum = 63
            },
            new Recipe
            {
                Id = 4, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Classic Roman pasta with eggs, cheese, pancetta, and black pepper.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper", "Salt"],
                Steps = [
                    "Cook spaghetti in salted boiling water until al dente; reserve 1 cup pasta water.",
                    "Crisp pancetta in a large skillet over medium heat.",
                    "Whisk eggs and grated Pecorino Romano together in a bowl.",
                    "Drain pasta and add to the skillet with pancetta (off heat).",
                    "Pour egg mixture over pasta and toss quickly, adding pasta water to create a creamy sauce.",
                    "Season generously with black pepper and serve immediately."
                ],
                TotalRatings = 10, RatingSum = 45
            },
            new Recipe
            {
                Id = 5, Title = "Pad Thai", Category = "Thai",
                Description = "Stir-fried rice noodles with shrimp, peanuts, and a tangy sauce.",
                Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Green onions", "Peanuts", "Tamarind paste", "Fish sauce", "Sugar", "Lime"],
                Steps = [
                    "Soak rice noodles in warm water for 30 minutes; drain.",
                    "Mix tamarind paste, fish sauce, and sugar to make the sauce.",
                    "Stir-fry shrimp in a hot wok until pink; set aside.",
                    "Scramble eggs in the wok, then add noodles and sauce.",
                    "Toss with bean sprouts, green onions, and cooked shrimp.",
                    "Serve topped with crushed peanuts and lime wedges."
                ],
                TotalRatings = 6, RatingSum = 27
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh and creamy avocado dip with lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps = [
                    "Halve and pit avocados; scoop flesh into a bowl.",
                    "Mash with a fork to desired consistency.",
                    "Stir in diced onion, jalapeño, tomato, and chopped cilantro.",
                    "Add lime juice and salt to taste.",
                    "Serve immediately with tortilla chips."
                ],
                TotalRatings = 20, RatingSum = 90
            },
            new Recipe
            {
                Id = 7, Title = "Green Curry", Category = "Thai",
                Description = "Aromatic coconut curry with vegetables and your choice of protein.",
                Ingredients = ["Green curry paste", "Coconut milk", "Chicken or tofu", "Bamboo shoots", "Thai basil", "Bell pepper", "Fish sauce", "Sugar"],
                Steps = [
                    "Heat a splash of coconut milk in a pot until it separates.",
                    "Fry green curry paste in the coconut oil for 1 minute.",
                    "Add sliced chicken or tofu and cook until browned.",
                    "Pour in remaining coconut milk, bamboo shoots, and bell pepper.",
                    "Simmer for 15 minutes; season with fish sauce and sugar.",
                    "Stir in Thai basil and serve over jasmine rice."
                ],
                TotalRatings = 4, RatingSum = 17
            },
            new Recipe
            {
                Id = 8, Title = "Butter Chicken", Category = "Indian",
                Description = "Rich and creamy tomato-based chicken curry.",
                Ingredients = ["Chicken thighs", "Butter", "Tomato purée", "Heavy cream", "Garam masala", "Cumin", "Garlic", "Ginger", "Chili powder", "Fenugreek leaves"],
                Steps = [
                    "Marinate chicken in yogurt and spices for 1 hour.",
                    "Grill or pan-sear chicken until cooked through.",
                    "Melt butter in a pan; sauté garlic and ginger.",
