@page "/category/{CategoryName}"
@using RecipeHub.Services

@inject RecipeService Recipes

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (recipeList is null || recipeList.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in recipeList)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">
                            <a href="recipe/@recipe.Id">@recipe.Title</a>
                        </h4>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-warning mb-0">
                            @for (int i = 1; i <= 5; i++)
                            {
                                @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                            }
                            <span class="text-muted ms-1">(@recipe.TotalRatings ratings)</span>
                        </p>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeHub.Models.Recipe>? recipeList;

    protected override void OnParametersSet()
    {
        recipeList = Recipes.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Services

@inject RecipeService Recipes

@if (recipe is null)
{
    <PageTitle>Recipe Not Found — RecipeHub</PageTitle>
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <PageTitle>@recipe.Title — RecipeHub</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead text-muted">@recipe.Description</p>

    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">🥘 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h3>📝 Steps</h3>
            <ol class="list-group list-group-numbered">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeHub.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = Recipes.GetRecipeById(Id);
    }
}

@using RecipeHub.Services

@inject RecipeService Recipes

<div class="mb-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              class="fs-4"
              style="cursor: pointer; color: @(star <= selectedRating ? "#ffc107" : "#dee2e6");"
              @onclick="() => SubmitRating(star)">
            ★
        </span>
    }
    @if (submitted)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int selectedRating;
    private bool submitted;

    private void SubmitRating(int stars)
    {
        selectedRating = stars;
        Recipes.AddRating(RecipeId, stars);
        submitted = true;
    }
}

@page "/submit"
@using RecipeHub.Models
@using RecipeHub.Services
@rendermode InteractiveServer

@inject RecipeService Recipes
@inject NavigationManager Nav

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (!string.IsNullOrEmpty(successMessage))
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="submission.Title" placeholder="e.g., Grandma's Apple Pie" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputText id="category" class="form-control" @bind-Value="submission.Category" placeholder="e.g., Italian, Mexican, Thai" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="submission.Ingredients"
                       placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="submission.Steps"
                       placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients." />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeSubmission submission = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(submission.Title) ||
            string.IsNullOrWhiteSpace(submission.Category) ||
            string.IsNullOrWhiteSpace(submission.Ingredients) ||
            string.IsNullOrWhiteSpace(submission.Steps))
        {
            return;
        }

        var recipe = Recipes.AddRecipe(submission);
        successMessage = $"\"{recipe.Title}\" was added successfully!";
        submission = new();
    }
}

