@page "/category/{CategoryName}"
@using RecipeHub.Services

@inject RecipeService Recipes

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (recipeList is null || recipeList.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in recipeList)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">
                            <a href="recipe/@recipe.Id">@recipe.Title</a>
                        </h4>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-warning mb-0">
                            @for (int i = 1; i <= 5; i++)
                            {
                                @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                            }
                            <span class="text-muted ms-1">(@recipe.TotalRatings ratings)</span>
                        </p>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeHub.Models.Recipe>? recipeList;

    protected override void OnParametersSet()
    {
        recipeList = Recipes.GetRecipesByCategory(CategoryName);
    }
}

