            </div>
        </div>
        <div class="col-md-8">
            <h3>📝 Steps</h3>
            <ol class="list-group list-group-numbered">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

